template <std::size_t kIsNilOffset>
struct RuntimeRbIteratorNodeView
{
  static_assert(kIsNilOffset >= 0x0C, "RuntimeRbIteratorNodeView nil offset must be >= 0x0C");

  RuntimeRbIteratorNodeView* left;
  RuntimeRbIteratorNodeView* parent;
  RuntimeRbIteratorNodeView* right;
  std::uint8_t reserved[kIsNilOffset - 0x0C];
  std::uint8_t isNil;
};

using RuntimeRbIteratorNodeNil17 = RuntimeRbIteratorNodeView<0x11>;
using RuntimeRbIteratorNodeNil21 = RuntimeRbIteratorNodeView<0x15>;
using RuntimeRbIteratorNodeNil25 = RuntimeRbIteratorNodeView<0x19>;
using RuntimeRbIteratorNodeNil29 = RuntimeRbIteratorNodeView<0x1D>;
using RuntimeRbIteratorNodeNil14 = RuntimeRbIteratorNodeView<0x0E>;
using RuntimeRbIteratorNodeNil37 = RuntimeRbIteratorNodeView<0x25>;
using RuntimeRbIteratorNodeNil45 = RuntimeRbIteratorNodeView<0x2D>;
using RuntimeRbIteratorNodeNil53 = RuntimeRbIteratorNodeView<0x35>;
using RuntimeRbIteratorNodeNil57 = RuntimeRbIteratorNodeView<0x39>;
using RuntimeRbIteratorNodeNil61 = RuntimeRbIteratorNodeView<0x3D>;
using RuntimeRbIteratorNodeNil65 = RuntimeRbIteratorNodeView<0x41>;
using RuntimeRbIteratorNodeNil89 = RuntimeRbIteratorNodeView<0x59>;
using RuntimeRbIteratorNodeNil3273 = RuntimeRbIteratorNodeView<0xCC9>;

template <std::size_t kIsNilOffset>
[[nodiscard]] inline RuntimeRbIteratorNodeView<kIsNilOffset>* RuntimeAdvanceRbIteratorSlotCommon(
  RuntimeRbIteratorNodeView<kIsNilOffset>** const iteratorSlot
) noexcept
{
  auto* node = *iteratorSlot;
  if (node->isNil != 0u) {
    return node;
  }

  auto* right = node->right;
  if (right->isNil == 0u) {
    node = right->left;
    if (node->isNil == 0u) {
      do {
        right = node;
        node = node->left;
      } while (node->isNil == 0u);
    }
    *iteratorSlot = right;
    return node;
  }

  node = node->parent;
  if (node->isNil != 0u) {
    *iteratorSlot = node;
    return node;
  }

  while (*iteratorSlot == node->right) {
    *iteratorSlot = node;
    node = node->parent;
    if (node->isNil != 0u) {
      break;
    }
  }

  *iteratorSlot = node;
  return node;
}

template <std::size_t kIsNilOffset>
[[nodiscard]] inline RuntimeRbIteratorNodeView<kIsNilOffset>* RuntimeFindRbSubtreeLeftmostCommon(
  RuntimeRbIteratorNodeView<kIsNilOffset>* node
) noexcept
{
  if (node == nullptr) {
    return nullptr;
  }

  auto* cursor = node->left;
  if (cursor == nullptr || cursor->isNil != 0u) {
    return node;
  }

  do {
    node = cursor;
    cursor = cursor->left;
  } while (cursor != nullptr && cursor->isNil == 0u);

  return node;
}

template <std::size_t kIsNilOffset>
[[nodiscard]] inline RuntimeRbIteratorNodeView<kIsNilOffset>* RuntimeFindRbSubtreeRightmostCommon(
  RuntimeRbIteratorNodeView<kIsNilOffset>* node
) noexcept
{
  if (node == nullptr) {
    return nullptr;
  }

  auto* cursor = node->right;
  if (cursor == nullptr || cursor->isNil != 0u) {
    return node;
  }

  do {
    node = cursor;
    cursor = cursor->right;
  } while (cursor != nullptr && cursor->isNil == 0u);

  return node;
}

